15	
16	@Service
17	@RequiredArgsConstructor
18	public class LeaveService {
19	
20	    private final LeaveRequestRepository leaveRequestRepository;
21	    private final ApprovalRecordRepository approvalRecordRepository;
22	    private final UserRepository userRepository;
23	
24	    @Transactional
25	    public LeaveRequest submitLeave(Long applicantId, LeaveSubmitDTO dto) {
26	        User applicant = userRepository.getReferenceById(applicantId);
27	        LeaveRequest request = new LeaveRequest();
28	        request.setApplicant(applicant);
29	        request.setLeaveType(dto.getLeaveType());
30	        request.setStartDate(dto.getStartDate());
31	        request.setEndDate(dto.getEndDate());
32	        request.setReason(dto.getReason());
33	        request.setStatus("PENDING");
34	        return leaveRequestRepository.save(request);
35	    }
36	
37	    @Transactional
38	    public void approveLeave(Long requestId, Long approverId, String action, String comment) {
39	        LeaveRequest request = leaveRequestRepository.findById(requestId)
40	                .orElseThrow(() -> new RuntimeException("请假单不存在"));
41	        if (!"PENDING".equals(request.getStatus())) {
42	            throw new RuntimeException("该请假单已处理");
43	        }
44	
45	        User approver = userRepository.getReferenceById(approverId);
46	        request.setStatus("APPROVE".equals(action) ? "APPROVED" : "REJECTED");
47	        leaveRequestRepository.save(request);
48	
49	        ApprovalRecord record = new ApprovalRecord();
50	        record.setLeaveRequest(request);
51	        record.setApprover(approver);
52	        record.setAction(action);
53	        record.setComment(comment);
54	        approvalRecordRepository.save(record);
55	    }
56	
57	    public List<LeaveRequest> getMyRequests(Long applicantId) {
58	        return leaveRequestRepository.findByApplicantIdOrderByCreateTimeDesc(applicantId);
59	    }
60	
61	    public List<LeaveRequest> getPendingRequests() {
62	        return leaveRequestRepository.findByStatusOrderByCreateTimeDesc("PENDING");
63	    }
64	
65	    public LeaveRequest getRequestDetail(Long requestId) {
